UPDATE public.system_settings
SET value = jsonb_build_object(
  'content', E'# CHINH SACH HE THONG TEAMWORKS UEH\n\n**Phien ban:** 1.0 | **Cap nhat:** 08/03/2026 | **Hieu luc:** Ngay ban hanh\n\n---\n\n## MUC LUC\n\n1. Gioi thieu & Pham vi\n2. Tai khoan & Xac thuc\n3. Vai tro & Quyen han\n4. Quy tac su dung du an\n5. Luu tru & Dung luong\n6. Cham diem & Khieu nai\n7. Giao tiep & Ung xu\n8. **CAC DIEU BI CAM**\n9. Tam dinh chi & Xu ly vi pham\n10. Bao tri he thong\n11. Quyen rieng tu & Du lieu\n12. Dieu khoan cuoi\n\n---\n\n## 1. GIOI THIEU & PHAM VI AP DUNG\n\n### 1.1 Gioi thieu\nTeamworks UEH la nen tang **quan ly cong viec nhom truc tuyen** danh rieng cho sinh vien Dai hoc Kinh te TP. Ho Chi Minh (UEH). He thong ho tro:\n- Phan cong va theo doi cong viec nhom\n- Cham diem qua trinh tu dong\n- Luu tru tai lieu va tai nguyen du an\n- Giao tiep va hop truc tuyen\n- Xuat bao cao minh chung du an\n\n### 1.2 Pham vi ap dung\nChinh sach nay ap dung cho **tat ca nguoi dung** su dung he thong, bao gom:\n- Quan tri vien he thong (Admin)\n- Thanh vien Nang cao (Leader)\n- Thanh vien (Member)\n\n> **Luu y:** Bang viec dang ky va su dung he thong, nguoi dung **xac nhan da doc, hieu va dong y** tuan thu toan bo chinh sach nay.\n\n---\n\n## 2. TAI KHOAN & XAC THUC\n\n### 2.1 Dang ky tai khoan\n- **Bat buoc:** Email UEH, Ma so sinh vien (MSSV), Ho ten day du\n- Tai khoan sau dang ky can duoc **Admin duyet** truoc khi su dung\n- Moi MSSV chi duoc dang ky **mot tai khoan duy nhat**\n- Khong chap nhan email ca nhan (Gmail, Yahoo...)\n\n### 2.2 Bao mat tai khoan\n- Mat khau toi thieu **6 ky tu**\n- Tai khoan duoc Leader tao se bat buoc **doi mat khau lan dau**\n- Nguoi dung **chiu toan bo trach nhiem** voi moi hanh dong tren tai khoan\n- Phai bao ngay cho Admin neu nghi ngo tai khoan bi xam nhap\n\n### 2.3 Khoi phuc mat khau\n- Su dung chuc nang \"Quen mat khau\" tren trang dang nhap\n- Ma OTP gui qua email, co hieu luc **gioi han thoi gian**\n- Toi da 3 lan yeu cau OTP trong 1 gio\n\n---\n\n## 3. VAI TRO & QUYEN HAN\n\n### 3.1 Quan tri vien (Admin)\n| Quyen | Mo ta |\n|-------|-------|\n| Quan ly nguoi dung | Duyet/tu choi/tam dinh chi tai khoan |\n| Quan ly du an | Truy cap toan bo du an trong he thong |\n| Cai dat he thong | Bao tri, chinh sach, ghi log |\n| Sao luu | Quan ly backup va restore du lieu |\n| Khong gioi han | Dung luong, so du an, truy cap |\n\n### 3.2 Thanh vien Nang cao (Leader)\n| Quyen | Mo ta |\n|-------|-------|\n| Tao du an | Tao va quan ly nhom du an |\n| Quan ly task | Tao giai doan, task, phan cong |\n| Cham diem | Cham diem qua trinh cho thanh vien |\n| Quan ly thanh vien | Them/xoa thanh vien, phan quyen |\n| Tai nguyen | Upload/quan ly file va link du an |\n| Xuat bao cao | Xuat PDF minh chung du an |\n\n### 3.3 Thanh vien (Member)\n| Quyen | Mo ta |\n|-------|-------|\n| Xem task | Xem cac task duoc phan cong |\n| Nop bai | Upload file hoac gui link |\n| Xem diem | Xem diem qua trinh ban than |\n| Khieu nai | Gui appeal khi khong dong y diem |\n| Giao tiep | Binh luan, nhan tin trong du an |\n| Hop truc tuyen | Tham gia phong hop video |\n\n---\n\n## 4. QUY TAC SU DUNG DU AN\n\n### 4.1 Noi dung du an\n- Noi dung phai **phu hop muc dich hoc tap** tai UEH\n- Leader chiu trach nhiem chinh voi noi dung du an\n- Moi du an phai co **ten ro rang**, mo ta cu the\n\n### 4.2 Deadline & Nop bai\n- Thanh vien **bat buoc nop bai truoc deadline**\n- Nop tre se bi **tru diem tu dong** theo cong thuc he thong\n- Leader co quyen gia han deadline trong truong hop dac biet\n- Ho tro 2 hinh thuc: **Upload file** hoac **Nop link**\n- File phai dung dinh dang va khong vuot kich thuoc cho phep\n\n### 4.3 Giai doan du an (Stages)\n- Du an duoc chia thanh cac giai doan co trong so rieng\n- Moi giai doan co ngay bat dau/ket thuc rieng\n- Leader co the an/hien giai doan tuy theo tien do\n\n---\n\n## 5. LUU TRU & DUNG LUONG\n\n### 5.1 Han muc mac dinh\n| Vai tro | Dung luong | Ghi chu |\n|---------|------------|--------|\n| Member | **200 MB** | Co the duoc Admin dieu chinh |\n| Leader | **200 MB** | Tuong tu Member |\n| Admin | **Khong gioi han** | |\n\n### 5.2 Khi vuot han muc\n- **Khong the** upload file moi\n- Chi co the nop bai bang **link**\n- Can xoa file cu hoac lien he Admin tang han muc\n\n### 5.3 Cac loai file ho tro\n- Tai lieu: PDF, DOC, DOCX, XLS, XLSX, PPT, PPTX\n- Hinh anh: JPG, PNG, GIF, WEBP\n- Nen: ZIP, RAR\n- Khac: Theo cai dat cua tung task\n\n---\n\n## 6. CHAM DIEM & KHIEU NAI\n\n### 6.1 Cong thuc tinh diem\n\n**Diem task:**\n- Diem co ban (Base Score): 0-10\n- Phat tre han (Late Penalty): Tru theo so ngay/gio nop tre\n- Phat review (Review Penalty): Tru khi bi yeu cau sua nhieu lan\n- Bonus nop som (Early Bonus): +0.5 khi nop truoc 24h\n- Bonus Bug Hunter: +0.5 khi phat hien loi quan trong\n\n**Diem giai doan:**\n- = Trung binh diem task x He so K\n- He so K dieu chinh theo muc do dong gop tong the\n\n**Diem tong ket:**\n- = Trung binh co trong cac giai doan\n- Leader co the dieu chinh (+/-) voi ly do ro rang\n\n### 6.2 Khieu nai diem (Appeal)\n- Thanh vien co quyen khieu nai diem task hoac giai doan\n- **Yeu cau:**\n  - Ly do cu the, ro rang\n  - Minh chung (file dinh kem neu can)\n  - Gui trong thoi han cho phep\n- Leader/Admin xem xet va phan hoi\n- Ket qua: **Chap nhan** (dieu chinh diem) hoac **Tu choi** (giu nguyen + giai thich)\n\n---\n\n## 7. GIAO TIEP & UNG XU\n\n### 7.1 Quy tac giao tiep\n- Su dung ngon ngu **lich su, ton trong** trong moi tin nhan va binh luan\n- Tra loi tin nhan nhom trong **thoi gian hop ly**\n- Su dung chuc nang @mention de goi dung nguoi can thiet\n- Khong gui tin nhan spam hoac khong lien quan den du an\n\n### 7.2 Hop truc tuyen\n- Tham gia dung gio da hen\n- Bat camera khi duoc yeu cau\n- Ghi chu cuoc hop day du\n- Leader co quyen diem danh tu dong\n\n---\n\n## 8. CAC DIEU BI CAM\n\n> **CANH BAO:** Vi pham cac dieu sau day se bi xu ly ngay lap tuc, bao gom tam dinh chi hoac khoa tai khoan vinh vien.\n\n### 8.1 Ve tai khoan\n- ❌ **Su dung tai khoan nguoi khac** hoac cho nguoi khac muon tai khoan\n- ❌ **Tao nhieu tai khoan** voi cung mot MSSV hoac email gia mao\n- ❌ **Gia mao danh tinh** (dung ten/MSSV nguoi khac)\n- ❌ **Chia se mat khau** hoac thong tin dang nhap\n- ❌ **Co gang truy cap trai phep** vao tai khoan Admin/Leader\n\n### 8.2 Ve noi dung\n- ❌ **Dang tai noi dung xuc pham**, phan biet doi xu, quay roi\n- ❌ **Noi dung khieu dam**, bao luc hoac vi pham phap luat\n- ❌ **Spam** tin nhan, binh luan, hoac tao task/du an vo nghia\n- ❌ **Quang cao** san pham/dich vu khong lien quan\n- ❌ **Vi pham ban quyen:** Sao chep noi dung khong co phep\n- ❌ **Dang tai ma doc**, virus hoac file co hai\n\n### 8.3 Ve hanh vi\n- ❌ **Co tinh pha hoai** du an cua nguoi khac (xoa du lieu, thay doi trai phep)\n- ❌ **Lam dung chuc nang khieu nai** (gui appeal vo co, spam appeal)\n- ❌ **Thao tung diem so** hoac cau ket de gian lan diem\n- ❌ **Tu y thay doi vai tro** hoac quyen han cua nguoi khac\n- ❌ **Khai thac lo hong** he thong de truc loi\n- ❌ **Su dung tool/bot** tu dong de thao tac he thong\n- ❌ **Tu choi hop tac nhom** ma khong co ly do chinh dang\n\n### 8.4 Ve du lieu\n- ❌ **Thu thap thong tin ca nhan** cua nguoi dung khac voi muc dich xau\n- ❌ **Phat tan du lieu** noi bo cua du an ra ben ngoai khi chua duoc phep\n- ❌ **Xoa du lieu co chu dich** de gay thiet hai cho nhom\n- ❌ **Truy cap trai phep** vao du lieu cua du an khong thuoc ve minh\n\n---\n\n## 9. TAM DINH CHI & XU LY VI PHAM\n\n### 9.1 Cap do xu ly\n\n| Cap do | Thoi gian | Ap dung cho |\n|--------|-----------|------------|\n| **Canh cao** | Khong khoa | Vi pham lan dau, muc do nhe |\n| **Dinh chi nhe** | 1 - 24 gio | Spam, ngon ngu khong phu hop |\n| **Dinh chi trung binh** | 1 - 7 ngay | Co tinh pha hoai, lam dung |\n| **Dinh chi nghiem trong** | 30 ngay | Vi pham nghiem trong, tai pham |\n| **Khoa vinh vien** | Khong thoi han | Gia mao, hack, vi pham phap luat |\n\n### 9.2 Quyen cua Admin\n- Admin co **toan quyen** tam dinh chi bat ky tai khoan nao\n- Phai ghi ro **ly do dinh chi** trong he thong\n- Co the **gia han hoac giam** thoi gian dinh chi\n\n### 9.3 Trong thoi gian bi dinh chi\n- Khong the dang nhap vao he thong\n- Hien thi man hinh thong bao: ly do + thoi gian con lai\n- Sau khi het han: tai khoan **tu dong mo khoa**\n- Du lieu va du an **khong bi xoa** trong thoi gian dinh chi\n\n### 9.4 Khang nghi\n- Nguoi bi dinh chi co the **gui feedback** qua he thong (neu con truy cap)\n- Hoac lien he truc tiep Admin qua email\n- Admin xem xet va phan hoi trong **48 gio lam viec**\n\n---\n\n## 10. BAO TRI HE THONG\n\n### 10.1 Che do bao tri\n- Admin co quyen **bat/tat che do bao tri** bat ky luc nao\n- Khi bat: toan bo nguoi dung (tru Admin) thay **man hinh bao tri**\n- Thong bao bao gom: ly do, thoi gian du kien hoan thanh\n\n### 10.2 Sao luu du lieu\n- He thong ho tro **sao luu va khoi phuc** du lieu du an\n- Admin co the xuat backup JSON cua toan bo du an\n- Khuyen khich Leader tu sao luu du lieu quan trong\n\n---\n\n## 11. QUYEN RIENG TU & DU LIEU\n\n### 11.1 Bao ve du lieu\n- Du lieu duoc bao ve boi **chinh sach truy cap nghiem nhat (RLS)**\n- Nguoi dung chi xem duoc du lieu cua du an minh tham gia\n- Thong tin ca nhan chi hien thi cho thanh vien cung du an\n- Mat khau duoc **ma hoa** va khong ai co the xem\n\n### 11.2 Chia se cong khai\n- Leader co the bat/tat **che do cong khai** cho du an\n- Khi cong khai, nguoi ngoai co the xem:\n  - Danh sach thanh vien\n  - Danh sach tasks va tien do\n  - Tai nguyen du an\n  - Nhat ky hoat dong\n- **KHONG BAO GIO** cong khai: diem so, tin nhan, thong tin nhay cam\n\n### 11.3 Ho so cong khai\n- Nguoi dung **tu nguyen** tao username de co trang ho so cong khai\n- Hien thi: ten, bio, ky nang, thanh tuu\n- Khong bat buoc - chi khi tu thiet lap\n\n---\n\n## 12. DIEU KHOAN CUOI\n\n### 12.1 Hieu luc\n- Chinh sach co hieu luc tu ngay ban hanh\n- Ap dung cho tat ca nguoi dung hien tai va tuong lai\n\n### 12.2 Cap nhat\n- Admin co quyen **cap nhat chinh sach** bat ky luc nao\n- Nguoi dung se duoc thong bao khi co thay doi quan trong\n- Phien ban va ngay hieu luc duoc ghi ro o dau van ban\n\n### 12.3 Dong y\n- Tiep tuc su dung he thong = **Dong y toan bo chinh sach**\n- Neu khong dong y, nguoi dung co quyen ngung su dung\n- Viec ngung su dung khong anh huong den du lieu da tao truoc do\n\n### 12.4 Lien he\n- Moi thac mac ve chinh sach, vui long gui **Feedback** qua he thong\n- Hoac lien he Admin qua email duoc cung cap trong trang quan tri\n\n---\n\n*© 2025-2026 Teamworks UEH - Dai hoc Kinh te TP. Ho Chi Minh*\n*Moi quyen duoc bao luu.*',
  'updated_at', to_char(now(), 'YYYY-MM-DD"T"HH24:MI:SS"Z"')
),
updated_at = now()
WHERE key = 'system_policy';